// ============================================================
// DAILY SUMMARY REPORT
// Node duy nhất: tính ngày, query Supabase, format tin nhắn
// try/catch toàn bộ → luôn trả đúng 1 output item
// ============================================================

const SUPABASE = 'https://fpesidoqwxyyutgvalsp.supabase.co/rest/v1';
const KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZwZXNpZG9xd3h5eXV0Z3ZhbHNwIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NTY3NDkzNywiZXhwIjoyMDkxMjUwOTM3fQ.X9s9a_rSNefhdd7UEsTulNB1xct4JK_QZe2UzIubPg8';
const HEADERS = { apikey: KEY, Authorization: `Bearer ${KEY}` };
const CHAT_ID = '-5163098733';

// --- Tính ngày SGT ---
const now = new Date();
const SGT_OFFSET = 7 * 60 * 60 * 1000;
const sgtNow = new Date(now.getTime() + SGT_OFFSET);
const sgtDateStr = sgtNow.toISOString().split('T')[0];
const startDate = new Date(sgtDateStr + 'T00:00:00+07:00');
const endDate = now;
const [yyyy, mm, dd] = sgtDateStr.split('-');
const dateDisplay = `${dd}/${mm}/${yyyy}`;

let candidates = [];
let orders = [];
let errorNotes = '';

// --- Query candidates (toàn bộ, filter ngày trong JS) ---
try {
  const r = await fetch(`${SUPABASE}/candidates?select=id_ld,full_name,order_id,interview_status,synced_at&order=synced_at.desc&limit=500`, { headers: HEADERS });
  const all = await r.json();
  candidates = Array.isArray(all) ? all.filter(c => {
    const t = new Date(c.synced_at);
    return t >= startDate && t < endDate;
  }) : [];
} catch (e) {
  errorNotes += `[candidates: ${e.message}] `;
}

// --- Query orders còn thiếu lao động ---
try {
  const r = await fetch(`${SUPABASE}/orders?select=id,company_name,job_type,total_labor,labor_missing&labor_missing=gt.0&order=created_at.desc`, { headers: HEADERS });
  const data = await r.json();
  orders = Array.isArray(data) ? data : [];
} catch (e) {
  errorNotes += `[orders: ${e.message}] `;
}

// --- Format tin nhắn ---
let text = `📊 *BÁO CÁO NGÀY ${dateDisplay}*\n`;
text += `━━━━━━━━━━━━━━━━━━\n\n`;

if (candidates.length === 0) {
  text += `🆕 *Ứng viên mới hôm nay:* Không có\n`;
} else {
  text += `🆕 *Ứng viên mới hôm nay: ${candidates.length} người*\n`;
  const byOrder = {};
  for (const c of candidates) {
    const key = c.order_id || 'Chưa phân đơn';
    if (!byOrder[key]) byOrder[key] = { pass: 0, fail: 0, pending: 0 };
    const s = (c.interview_status || '').toLowerCase();
    if (s === 'pass') byOrder[key].pass++;
    else if (s === 'fail') byOrder[key].fail++;
    else byOrder[key].pending++;
  }
  for (const [orderId, stats] of Object.entries(byOrder)) {
    const total = stats.pass + stats.fail + stats.pending;
    const parts = [];
    if (stats.pass > 0) parts.push(`✅ ${stats.pass}`);
    if (stats.fail > 0) parts.push(`❌ ${stats.fail}`);
    if (stats.pending > 0) parts.push(`⏳ ${stats.pending}`);
    text += `  📦 ${orderId}: ${total} người — ${parts.join(' / ')}\n`;
  }
}

text += `\n`;

if (orders.length === 0) {
  text += `📋 *Đơn hàng:* Tất cả đã đủ lao động 🎉`;
} else {
  const totalMissing = orders.reduce((s, o) => s + (parseInt(o.labor_missing) || 0), 0);
  text += `📋 *Đơn hàng đang tuyển: ${orders.length} đơn — còn thiếu ${totalMissing} suất*\n`;
  for (const o of orders.slice(0, 8)) {
    text += `  • ${o.company_name} — ${o.job_type}: còn thiếu *${o.labor_missing}/${o.total_labor}*\n`;
  }
  if (orders.length > 8) text += `  _...và ${orders.length - 8} đơn khác_\n`;
}

if (errorNotes) text += `\n⚠️ _Lỗi query: ${errorNotes}_`;

return [{ json: { text, chat_id: CHAT_ID } }];
